import { NextResponse } from 'next/server';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { disputeId, decision, adminId } = body;

    // 1. التحقق الأمني (Authorization)
    if (!disputeId || !decision) {
      return NextResponse.json({ success: false, error: 'بيانات القرار غير مكتملة' }, { status: 400 });
    }

    // 2. محاكاة المعالجة المالية والقانونية (Supabase & Escrow Logic)
    // - إذا كان القرار 'freelancer': نقل الأموال من Escrow إلى Available Balance للمستقل
    // - إذا كان القرار 'client': إصدار أمر Refund لبوابة الدفع (Paymob/PayPal)
    // await supabase.from('escrow_transactions').update({ status: decision }).eq('dispute_id', disputeId);

    // 3. توليد رقم تدقيق قانوني (Audit Trail ID)
    const auditId = `AUD-${Date.now().toString().slice(-6)}-${Math.floor(Math.random() * 1000)}`;

    return NextResponse.json({
      success: true,
      message: 'تم تنفيذ القرار السيادي وتوجيه الأموال بنجاح',
      data: {
        disputeId,
        resolution: decision === 'freelancer' ? 'لصالح المبدع' : 'إعادة للعميل',
        auditId,
        timestamp: new Date().toISOString()
      }
    });

  } catch (error) {
    return NextResponse.json({ success: false, error: 'خطأ داخلي في الخادم أثناء تنفيذ القرار' }, { status: 500 });
  }
}

import { activateSovereignAgreement } from '@/lib/contracts';
import { NextResponse } from 'next/server';
import crypto from 'crypto';
import { supabase } from '@/lib/supabase';

const PAYMOB_HMAC = process.env.PAYMOB_HMAC_SECRET || 'secret_mcos_key';

export async function POST(req: Request) {
  try {
    const body = await req.text();
    const hmacHeader = req.headers.get('hmac');

    if (!hmacHeader) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const calculatedHmac = crypto.createHmac('sha512', PAYMOB_HMAC).update(body).digest('hex');
    if (calculatedHmac !== hmacHeader) return NextResponse.json({ error: 'Invalid HMAC' }, { status: 403 });

    const data = JSON.parse(body);
    const orderId = data.obj.order.merchant_order_id;

    if (data.obj.success) {
      const { data: job } = await supabase.from('jobs').select('*').eq('id', orderId).single();
      if (job) {
        await activateSovereignAgreement(job.id, job.client_id, job.freelancer_id, job.budget);
        await supabase.from('jobs').update({ status: 'in_progress', escrow_secured: true }).eq('id', orderId);
        await supabase.from('transactions').insert({
          reference_id: orderId,
          user_id: job.client_id,
          job_id: orderId,
          amount: data.obj.amount_cents / 100,
          status: 'completed',
          type: 'escrow_hold'
        });
      }
    }
    return NextResponse.json({ success: true });
  } catch (e) {
    return NextResponse.json({ error: 'Internal Error' }, { status: 500 });
  }
}

