'use client';
import React, { useState } from 'react';
import { Skull, Database, WifiOff, ShieldAlert, Play, RotateCcw } from 'lucide-react';
import { InteractiveButton } from '@/components/system/InteractiveButton';
import { motion, AnimatePresence } from 'framer-motion';

export function ChaosControl() {
  const [logs, setLogs] = useState<string[]>([]);
  const [systemHealth, setSystemHealth] = useState(100);

  const addLog = (msg: string) => setLogs(prev => [msg, ...prev].slice(0, 5));

  const triggerChaos = (type: string) => {
    addLog(`[CHAOS] Initiating ${type} attack...`);
    setSystemHealth(prev => Math.max(0, prev - 30));

    // Simulate Self-Healing
    setTimeout(() => {
       addLog(`[SYSTEM] Anomaly detected. Rerouting traffic.`);
    }, 1500);
    setTimeout(() => {
       addLog(`[SYSTEM] New replica spawned. Health restoring.`);
       setSystemHealth(prev => Math.min(100, prev + 30));
    }, 3500);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
       {/* Attack Panel */}
       <div className="bg-red-950/20 border border-red-500/30 rounded-xl p-6 relative overflow-hidden">
          <div className="absolute -right-4 -top-4 opacity-10 rotate-12"><Skull size={150} /></div>

          <h3 className="font-bold text-red-400 mb-6 flex items-center gap-2">
             <Skull size={24} /> منطقة اختبار الكوارث (Chaos Zone)
          </h3>

          <div className="space-y-4 relative z-10">
             <div className="flex items-center justify-between p-4 bg-black/40 border border-red-500/20 rounded-xl">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-red-500/10 rounded text-red-400"><Database size={20}/></div>
                   <div>
                      <div className="text-white font-bold text-sm">Kill Primary DB</div>
                      <div className="text-[10px] text-red-300">Simulate database crash</div>
                   </div>
                </div>
                <InteractiveButton variant="danger" size="sm" onClick={() => triggerChaos('DB_CRASH')}>EXECUTE</InteractiveButton>
             </div>

             <div className="flex items-center justify-between p-4 bg-black/40 border border-red-500/20 rounded-xl">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-red-500/10 rounded text-red-400"><WifiOff size={20}/></div>
                   <div>
                      <div className="text-white font-bold text-sm">Sever Region EU</div>
                      <div className="text-[10px] text-red-300">Cut connection to Europe</div>
                   </div>
                </div>
                <InteractiveButton variant="danger" size="sm" onClick={() => triggerChaos('NET_SPLIT')}>EXECUTE</InteractiveButton>
             </div>
          </div>
       </div>

       {/* System Response Console */}
       <div className="bg-black border border-white/10 rounded-xl p-6 font-mono text-xs flex flex-col h-[300px]">
          <div className="flex justify-between items-center mb-4 border-b border-white/10 pb-2">
             <span className="text-slate-400">System Logs</span>
             <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${systemHealth === 100 ? 'bg-green-500' : 'bg-red-500 animate-pulse'}`} />
                <span className={systemHealth === 100 ? 'text-green-400' : 'text-red-400'}>Health: {systemHealth}%</span>
             </div>
          </div>

          <div className="flex-1 overflow-hidden relative space-y-2">
             <AnimatePresence>
                {logs.map((log, i) => (
                   <motion.div 
                     key={i}
                     initial={{ opacity: 0, x: -20 }}
                     animate={{ opacity: 1, x: 0 }}
                     className="flex gap-2"
                   >
                      <span className="text-slate-600">[{new Date().toLocaleTimeString()}]</span>
                      <span className={log.includes('CHAOS') ? 'text-red-400 font-bold' : 'text-green-400'}>{log}</span>
                   </motion.div>
                ))}
             </AnimatePresence>
             {logs.length === 0 && <div className="text-slate-700 italic">System stable. Waiting for input...</div>}
          </div>
       </div>
    </div>
  );
}

'use client';
import React, { useState, useEffect } from 'react';
import { Activity, Server, Cpu, Database, ArrowUp } from 'lucide-react';
import { motion } from 'framer-motion';

export function PerformanceDashboard() {
  const [load, setLoad] = useState(45);
  const [pods, setPods] = useState(3);

  // Simulate Load Spikes & Auto-Scaling
  useEffect(() => {
    const interval = setInterval(() => {
      setLoad(prev => {
        const newLoad = prev + (Math.random() * 20 - 8);
        const clampedLoad = Math.min(100, Math.max(10, newLoad));

        // Auto-Scale Logic Simulation
        if (clampedLoad > 80) setPods(p => Math.min(12, p + 1));
        if (clampedLoad < 40) setPods(p => Math.max(2, p - 1));

        return clampedLoad;
      });
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
       {/* Live Metrics */}
       <div className="lg:col-span-2 space-y-6">
          <div className="bg-slate-900 border border-white/10 rounded-xl p-6">
             <div className="flex justify-between items-center mb-6">
                <h3 className="font-bold text-white flex items-center gap-2">
                   <Activity className="text-green-400" /> حمل النظام (System Load)
                </h3>
                <span className="text-xs font-mono text-slate-500">Live Update: 200ms</span>
             </div>

             {/* Chart Simulation */}
             <div className="h-48 flex items-end gap-1 overflow-hidden relative">
                <div className="absolute inset-0 border-t border-dashed border-red-500/30 top-[20%] text-[10px] text-red-500">Critical Threshold</div>
                {Array.from({length: 40}).map((_, i) => (
                   <motion.div 
                     key={i}
                     initial={{ height: '10%' }}
                     animate={{ height: `${(i * 17) % 70 + 10}%` }}
                     transition={{ duration: 0.5 }}
                     className={`flex-1 rounded-t-sm ${load > 80 ? 'bg-red-500' : 'bg-indigo-500'}`}
                   />
                ))}
             </div>
             <div className="mt-4 flex justify-between text-xs text-slate-400 font-mono">
                <span>CPU: {Math.round(load)}%</span>
                <span>RAM: {Math.round(load * 0.8)}%</span>
                <span>IOPS: 4.2k</span>
             </div>
          </div>
       </div>

       {/* Kubernetes Cluster State */}
       <div className="bg-[#0a0a0a] border border-white/10 rounded-xl p-6 flex flex-col">
          <h3 className="font-bold text-white mb-6 flex items-center gap-2">
             <Server className="text-blue-400" /> البنية السحابية (K8s Cluster)
          </h3>

          <div className="flex-1 grid grid-cols-2 gap-4 content-start">
             {Array.from({length: pods}).map((_, i) => (
                <motion.div 
                  layout
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  key={i}
                  className="bg-slate-900 border border-white/5 p-3 rounded-lg flex flex-col items-center justify-center gap-2 relative overflow-hidden"
                >
                   <div className="absolute top-1 right-1 w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_#22c55e]" />
                   <Cpu size={20} className="text-slate-400" />
                   <div className="text-[10px] font-mono text-slate-300">Node-{i+10}</div>
                   <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                      <div className="h-full bg-green-500" style={{ width: `${(i * 13) % 80 + 20}%` }}></div>
                   </div>
                </motion.div>
             ))}

             {/* Scaling Indicator */}
             {load > 70 && (
                <motion.div 
                   initial={{ opacity: 0 }} 
                   animate={{ opacity: 1 }}
                   className="border-2 border-dashed border-white/10 p-3 rounded-lg flex flex-col items-center justify-center gap-1 text-slate-500"
                >
                   <ArrowUp size={20} className="animate-bounce" />
