                </motion.div>
             )}
          </div>

          <div className="mt-6 pt-4 border-t border-white/10 text-[10px] text-slate-500 text-center">
             Auto-scaling enabled (Min: 2, Max: 50)
          </div>
       </div>
    </div>
  );
}

