'use client';
import React, { useState, useEffect } from 'react';
import { Radio, Square, Play, Plus, Trash } from 'lucide-react';
import { Button } from '@/components/ui/Button';

export function MacroRecorder() {
  const [isRecording, setIsRecording] = useState(false);
  const [steps, setSteps] = useState<string[]>([]);
  const [timer, setTimer] = useState(0);

  useEffect(() => {
    let interval: unknown;
    if (isRecording) {
      interval = setInterval(() => setTimer(t => t + 1), 1000);
    } else {
      setTimer(0);
    }
    return () => clearInterval(interval);
  }, [isRecording]);

  const addStep = () => {
     // Simulation: In real app, this listens to global events
     const actions = ["Cut Clip", "Add Cross Dissolve", "Normalize Audio", "Apply Color Grade"];
     const randomAction = actions[Math.floor(Math.random() * actions.length)];
     setSteps([...steps, randomAction]);
  };

  return (
    <div className="bg-card border border-border rounded-xl p-4">
       <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
             <div className={`w-3 h-3 rounded-full ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-slate-300'}`} />
             <h3 className="font-bold text-sm">Macro Recorder</h3>
          </div>
          {isRecording && <span className="font-mono text-xs text-red-500">00:0{timer}</span>}
       </div>

       <div className="min-h-[150px] bg-muted/20 border border-border rounded-lg mb-4 p-2 space-y-1">
          {steps.length === 0 ? (
             <div className="h-full flex items-center justify-center text-xs text-muted-foreground italic">
                اضغط تسجيل لبدء تتبع الخطوات...
             </div>
          ) : (
             steps.map((step, i) => (
                <div key={i} className="text-xs bg-background border border-border px-2 py-1.5 rounded flex items-center gap-2 animate-in fade-in slide-in-from-left-2">
                   <span className="text-muted-foreground font-mono">{i + 1}.</span>
                   {step}
                </div>
             ))
          )}
       </div>

       <div className="flex gap-2">
          {!isRecording ? (
             <Button 
                className="flex-1 text-red-500 border-red-200 hover:bg-red-50" 
                variant="outline" 
                onClick={() => setIsRecording(true)}
                icon={<Radio size={14} />}
             >
                تسجيل
             </Button>
          ) : (
             <>
                <Button className="flex-1" variant="ghost" onClick={addStep} icon={<Plus size={14} />}>محاكاة خطوة</Button>
                <Button className="flex-1" variant="primary" onClick={() => setIsRecording(false)} icon={<Square size={14} />}>إيقاف وحفظ</Button>
             </>
          )}
          {steps.length > 0 && !isRecording && (
             <Button variant="outline" onClick={() => setSteps([])}><Trash size={14} /></Button>
          )}
       </div>
    </div>
  );
}

'use client';
import React, { useEffect, useState } from 'react';
import { Activity, Server, Shield, CheckCircle, XCircle, Terminal } from 'lucide-react';

export function RtcDebugger() {
  const [logs, setLogs] = useState<string[]>([]);
  const [status, setStatus] = useState<'connecting' | 'connected' | 'failed'>('connecting');

  useEffect(() => {
    const addLog = (msg: string) => setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

    // Simulation of WebRTC connection steps
    setTimeout(() => addLog('Initializing WebRTC PeerConnection...'), 500);
    setTimeout(() => addLog('Signaling Server: Connected (wss://signal.monteerly.com)'), 1000);
    setTimeout(() => addLog('Gathering ICE Candidates...'), 1500);
    setTimeout(() => addLog('STUN Server: stun.l.google.com:19302 (Found)'), 2000);
    setTimeout(() => {
        addLog('DTLS Handshake: Successful');
        addLog('Media Stream: Received (Video: H.264, Audio: Opus)');
        setStatus('connected');
    }, 3000);
  }, []);

  return (
    <div className="bg-black text-green-400 font-mono text-xs rounded-xl overflow-hidden border border-slate-800 w-full max-w-lg shadow-2xl">
       <div className="bg-slate-900 p-3 border-b border-slate-800 flex justify-between items-center">
          <div className="flex items-center gap-2">
             <Terminal size={14} />
             <span className="font-bold">تشخيص الاتصال (System Diagnostics)</span>
          </div>
          <div className="flex items-center gap-2">
             {status === 'connecting' && <Activity size={14} className="animate-pulse text-yellow-500" />}
             {status === 'connected' && <CheckCircle size={14} className="text-emerald-500" />}
             <span className="uppercase">{status}</span>
          </div>
       </div>

       <div className="p-4 space-y-4">
          <div className="grid grid-cols-3 gap-4 border-b border-slate-800 pb-4">
             <Metric icon={Server} label="Signaling" value="12ms" />
             <Metric icon={Activity} label="Bitrate" value="2.4 Mbps" />
             <Metric icon={Shield} label="Encryption" value="AES-128" />
          </div>

          <div className="h-48 overflow-y-auto space-y-1 pr-2 scrollbar-thin scrollbar-thumb-slate-700">
